// ── State ────────────────────────────────────────────────────
const ilogState = {
  view: "dashboard", // dashboard | detail | form
  activeId: null,
};

// ── Persistence ──────────────────────────────────────────────
const loadInterviews = () => {
  const raw = safeLocalStorageGet(STORAGE_KEY);
  if (raw) {
    try { return JSON.parse(raw); } catch (_) {
      // corrupted storage — fall through to seed
    }
  }
  safeLocalStorageSet(STORAGE_KEY, JSON.stringify(SEED_DATA));
  return SEED_DATA;
};

const saveInterviews = (data) => {
  safeLocalStorageSet(STORAGE_KEY, JSON.stringify(data));
};

// ── Helpers ──────────────────────────────────────────────────
const avgScore = (questions) => {
  const scored = questions.filter((q) => q.score !== null && q.score !== undefined && q.category !== "Candidate Questions");
  if (!scored.length) return null;
  return scored.reduce((s, q) => s + q.score, 0) / scored.length;
};

const scoreBadgeClass = (score) => {
  if (score === null || score === undefined) return "ilog-badge--grey";
  if (score >= 4) return "ilog-badge--green";
  if (score >= 3) return "ilog-badge--amber";
  return "ilog-badge--red";
};

const scorePillHtml = (score, qId, interviewId) => {
  const pills = [1, 2, 3, 4, 5]
    .map((n) => {
      const active = score === n ? " ilog-pill--active" : "";
      return `<button class="ilog-pill${active}" data-ilog-action="score" data-iid="${interviewId}" data-qid="${qId}" data-val="${n}">${n}</button>`;
    })
    .join("");
  return `<span class="ilog-pill-group">${pills}</span>`;
};

const categoryColor = (cat) => {
  const map = {
    "Motivation": "#8b5cf6",
    "General Fit": "#64748b",
    "Product Delivery": "#3b82f6",
    "Stakeholder Management": "#0891b2",
    "Compliance / Risk": "#dc2626",
    "Metrics & Impact": "#16a34a",
    "Leadership": "#d97706",
    "Logistics / Process": "#94a3b8",
    "Candidate Questions": "#e2e8f0",
  };
  return map[cat] || "#94a3b8";
};

const scoreLabel = (score) => {
  if (score === null || score === undefined) return "—";
  if (score >= 4.5) return "Excellent";
  if (score >= 4) return "Strong";
  if (score >= 3) return "Solid";
  if (score >= 2) return "Needs work";
  return "Weak";
};

const uid = () => "ilog_" + Date.now() + "_" + Math.random().toString(36).slice(2, 7);

// ── Gap Analysis ─────────────────────────────────────────────
const computeGaps = (interviews) => {
  const byTopic = {};
  for (const iv of interviews) {
    for (const q of iv.questions) {
      const cat = q.category;
      if (cat === "Candidate Questions") continue;
      if (q.score === null || q.score === undefined) continue;
      if (!byTopic[cat]) byTopic[cat] = { scores: [], count: 0 };
      byTopic[cat].scores.push(q.score);
      byTopic[cat].count++;
    }
  }
  return Object.entries(byTopic)
    .map(([topic, data]) => {
      const avg = data.scores.reduce((a, b) => a + b, 0) / data.scores.length;
      return { topic, avg: Math.round(avg * 10) / 10, count: data.count, guideId: TOPIC_TO_GUIDE[topic] || null };
    })
    .filter((g) => g.count >= 2 && g.avg <= 3.5)
    .sort((a, b) => a.avg - b.avg);
};

// ── Render: Dashboard ────────────────────────────────────────
const renderDashboard = (container) => {
  const interviews = loadInterviews();
  const totalQ = interviews.reduce((s, iv) => s + iv.questions.filter((q) => q.category !== "Candidate Questions").length, 0);
  const scoredQ = interviews.reduce((s, iv) => s + iv.questions.filter((q) => q.score !== null && q.score !== undefined && q.category !== "Candidate Questions").length, 0);
  const allScored = interviews.flatMap((iv) => iv.questions.filter((q) => q.score !== null && q.score !== undefined && q.category !== "Candidate Questions").map((q) => q.score));
  const globalAvg = allScored.length ? (allScored.reduce((a, b) => a + b, 0) / allScored.length).toFixed(1) : "—";
  const gaps = computeGaps(interviews);

  const cards = interviews
    .slice()
    .sort((a, b) => b.date.localeCompare(a.date))
    .map((iv) => {
      const avg = avgScore(iv.questions);
      const avgDisplay = avg !== null ? avg.toFixed(1) : "—";
      const badgeClass = scoreBadgeClass(avg);
      const qCount = iv.questions.filter((q) => q.category !== "Candidate Questions").length;
      return `
        <div class="ilog-card" data-ilog-action="view" data-iid="${iv.id}">
          <div class="ilog-card__top">
            <div class="ilog-card__company">${iv.company}</div>
            <span class="ilog-badge ${badgeClass}">${avgDisplay}</span>
          </div>
          <div class="ilog-card__role">${iv.role || "—"}</div>
          <div class="ilog-card__meta">${iv.stage} &middot; ${iv.date} &middot; ${qCount} questions</div>
          ${iv.headline ? `<div class="ilog-card__headline">${iv.headline}</div>` : ""}
        </div>`;
    })
    .join("");

  const weakGaps = gaps.slice(0, 6);
  const gapRows = weakGaps.length
    ? weakGaps
        .map((g) => {
          const bar = Math.round((g.avg / 5) * 100);
          const barColor = g.avg >= 3 ? "#d97706" : "#dc2626";
          const guideLink = g.guideId
            ? `<button class="ilog-gap-link" data-ilog-action="guide" data-guide="${g.guideId}">Open guide →</button>`
            : "";
          return `
          <div class="ilog-gap-row">
            <div class="ilog-gap-topic">${g.topic}</div>
            <div class="ilog-gap-bar-wrap">
              <div class="ilog-gap-bar" style="width:${bar}%;background:${barColor}"></div>
            </div>
            <div class="ilog-gap-avg">${g.avg} / 5</div>
            ${guideLink}
          </div>`;
        })
        .join("")
    : `<p class="ilog-gap-empty">No weak areas detected yet — keep scoring questions.</p>`;

  container.innerHTML = `
    <div class="ilog-shell">
      <div class="ilog-header">
        <div>
          <h1 class="ilog-header__title">Interview Log</h1>
          <p class="ilog-header__subtitle">Your real interview history — scored, analysed, and mapped to improvement areas.</p>
        </div>
        <button class="ilog-btn-primary" data-ilog-action="add">+ Add Interview</button>
      </div>

      <div class="ilog-stats-row">
        <div class="ilog-stat"><span class="ilog-stat__num">${interviews.length}</span><span class="ilog-stat__label">Interviews</span></div>
        <div class="ilog-stat"><span class="ilog-stat__num">${totalQ}</span><span class="ilog-stat__label">Questions</span></div>
        <div class="ilog-stat"><span class="ilog-stat__num">${globalAvg}</span><span class="ilog-stat__label">Avg score</span></div>
        <div class="ilog-stat"><span class="ilog-stat__num">${scoredQ}</span><span class="ilog-stat__label">Scored</span></div>
      </div>

      <div class="ilog-cards-grid">${cards}</div>

      <div class="ilog-gap-panel">
        <h2 class="ilog-gap-panel__title">Where to Improve</h2>
        <p class="ilog-gap-panel__sub">Topics where your average score is below 3.5 — sorted worst first.</p>
        <div class="ilog-gap-list">${gapRows}</div>
      </div>
    </div>`;
};

// ── Render: Detail ────────────────────────────────────────────
const renderDetail = (container, interviewId) => {
  const interviews = loadInterviews();
  const iv = interviews.find((i) => i.id === interviewId);
  if (!iv) { renderDashboard(container); return; }

  const displayQ = iv.questions.filter((q) => q.category !== "Candidate Questions");
  const avg = avgScore(iv.questions);

  const rows = displayQ
    .map((q) => {
      const catColor = categoryColor(q.category);
      const pills = scorePillHtml(q.score, q.id, iv.id);
      const scoreLabel_ = scoreLabel(q.score);
      const modelRow = q.model
        ? `<div class="ilog-q-model"><strong>Guide:</strong> ${q.model}</div>`
        : "";
      const notesVal = (q.notes || "").replace(/"/g, "&quot;");
      return `
        <div class="ilog-q-row">
          <div class="ilog-q-cat" style="border-color:${catColor};color:${catColor}">${q.category}</div>
          <div class="ilog-q-text">${q.text}</div>
          <div class="ilog-q-score">
            ${pills}
            <span class="ilog-q-score-label">${scoreLabel_}</span>
          </div>
          <details class="ilog-q-notes-wrap">
            <summary>Notes</summary>
            <textarea class="ilog-q-notes" rows="2" data-ilog-action="note" data-iid="${iv.id}" data-qid="${q.id}" placeholder="What you said / what to improve…">${notesVal}</textarea>
            ${modelRow}
          </details>
        </div>`;
    })
    .join("");

  const badgeClass = scoreBadgeClass(avg);
  const avgDisplay = avg !== null ? avg.toFixed(1) : "—";

  container.innerHTML = `
    <div class="ilog-shell">
      <button class="ilog-back" data-ilog-action="back">← Back to log</button>
      <div class="ilog-detail-header">
        <div>
          <h1 class="ilog-detail-header__company">${iv.company}</h1>
          <div class="ilog-detail-header__meta">${iv.role || "—"} &middot; ${iv.stage} &middot; ${iv.date}</div>
          ${iv.headline ? `<div class="ilog-detail-header__headline">${iv.headline}</div>` : ""}
        </div>
        <span class="ilog-badge ${badgeClass} ilog-badge--lg">${avgDisplay}</span>
      </div>
      ${iv.power ? `<div class="ilog-detail-insight ilog-detail-insight--green"><strong>Strengths:</strong> ${iv.power}</div>` : ""}
      ${iv.weak ? `<div class="ilog-detail-insight ilog-detail-insight--amber"><strong>Focus areas:</strong> ${iv.weak}</div>` : ""}
      <div class="ilog-q-list">${rows}</div>
    </div>`;
};

// ── Render: Add Form ──────────────────────────────────────────
const CATEGORIES = ["General Fit","Motivation","Product Delivery","Stakeholder Management","Compliance / Risk","Metrics & Impact","Leadership","Logistics / Process","Candidate Questions"];

const categoryOptions = (selected = "") => CATEGORIES.map((c) => `<option value="${c}"${c === selected ? " selected" : ""}>${c}</option>`).join("");

const questionRowHtml = (idx) => `
  <div class="ilog-form-qrow" data-qidx="${idx}">
    <div class="ilog-form-qrow__top">
      <span class="ilog-form-qrow__num">Q${idx + 1}</span>
      <select class="ilog-form-cat" name="cat_${idx}">${categoryOptions()}</select>
      <span class="ilog-form-score-label">Score:</span>
      ${[1,2,3,4,5].map((n) => `<button type="button" class="ilog-pill" data-form-score="${idx}" data-val="${n}">${n}</button>`).join("")}
      <button type="button" class="ilog-form-remove" data-remove="${idx}">✕</button>
    </div>
    <input type="text" class="ilog-form-q-text" name="q_${idx}" placeholder="Question asked…" autocomplete="off">
    <input type="text" class="ilog-form-notes" name="notes_${idx}" placeholder="Notes / what to improve…" autocomplete="off">
  </div>`;

const renderForm = (container) => {
  let qCount = 3;
  const stages = ["Phone Screen","1st Round","2nd Round","Final","Other"];

  const rebuildForm = () => {
    const rows = Array.from({ length: qCount }, (_, i) => questionRowHtml(i)).join("");
    container.innerHTML = `
      <div class="ilog-shell">
        <button class="ilog-back" data-ilog-action="back">← Back to log</button>
        <h1 class="ilog-form-title">Add Interview</h1>
        <form id="ilog-form" class="ilog-form" autocomplete="off">
          <div class="ilog-form-meta">
            <label class="ilog-form-label">Company<input class="ilog-form-input" name="company" placeholder="e.g. Monzo" required></label>
            <label class="ilog-form-label">Role<input class="ilog-form-input" name="role" placeholder="e.g. Senior PM"></label>
            <label class="ilog-form-label">Date<input class="ilog-form-input" type="date" name="date" value="${new Date().toISOString().slice(0, 10)}"></label>
            <label class="ilog-form-label">Stage
              <select class="ilog-form-input" name="stage">
                ${stages.map((s) => `<option>${s}</option>`).join("")}
              </select>
            </label>
          </div>
          <div id="ilog-form-questions">${rows}</div>
          <button type="button" class="ilog-btn-ghost" data-ilog-action="add-q">+ Add question</button>
          <div class="ilog-form-actions">
            <button type="submit" class="ilog-btn-primary">Save Interview</button>
          </div>
        </form>
      </div>`;
    attachFormListeners(container, () => qCount, (n) => { qCount = n; rebuildForm(); });
  };

  rebuildForm();
};

const attachFormListeners = (container, getCount, setCount) => {
  // Score pills in form
  container.querySelectorAll("[data-form-score]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const idx = btn.dataset.formScore;
      container.querySelectorAll(`[data-form-score="${idx}"]`).forEach((b) => b.classList.remove("ilog-pill--active"));
      btn.classList.add("ilog-pill--active");
    });
  });

  // Remove question row
  container.querySelectorAll("[data-remove]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const n = getCount();
      if (n > 1) setCount(n - 1);
    });
  });

  // Add question row
  const addBtn = container.querySelector("[data-ilog-action='add-q']");
  if (addBtn) {
    addBtn.addEventListener("click", () => setCount(getCount() + 1));
  }
};

// ── Save Form ─────────────────────────────────────────────────
const saveForm = (container) => {
  const form = container.querySelector("#ilog-form");
  if (!form) return;
  const fd = new FormData(form);

  const company = (fd.get("company") || "").trim();
  if (!company) { alert("Company name is required."); return; }

  const questions = [];
  const qrows = form.querySelectorAll(".ilog-form-qrow");
  qrows.forEach((row, idx) => {
    const text = (fd.get(`q_${idx}`) || "").trim();
    if (!text) return;
    const cat = fd.get(`cat_${idx}`) || "General Fit";
    const notes = (fd.get(`notes_${idx}`) || "").trim();
    const activePill = row.querySelector(".ilog-pill--active[data-form-score]");
    const score = activePill ? parseFloat(activePill.dataset.val) : null;
    questions.push({ id: uid(), text, category: cat, score, notes, model: "" });
  });

  const interviews = loadInterviews();
  interviews.unshift({
    id: uid(),
    company,
    role: (fd.get("role") || "").trim(),
    date: fd.get("date") || new Date().toISOString().slice(0, 10),
    stage: fd.get("stage") || "1st Round",
    headline: "",
    weak: "",
    power: "",
    questions,
  });
  saveInterviews(interviews);
  ilogState.view = "dashboard";
  renderIlog(container);
};

// ── Event delegation ──────────────────────────────────────────
const attachEvents = (container) => {
  container.addEventListener("click", (e) => {
    const btn = e.target.closest("[data-ilog-action]");
    if (!btn) return;
    const action = btn.dataset.ilogAction;

    if (action === "back") {
      ilogState.view = "dashboard";
      renderIlog(container);
    } else if (action === "add") {
      ilogState.view = "form";
      renderIlog(container);
    } else if (action === "view") {
      ilogState.view = "detail";
      ilogState.activeId = btn.dataset.iid;
      renderIlog(container);
    } else if (action === "score") {
      const interviews = loadInterviews();
      const iv = interviews.find((i) => i.id === btn.dataset.iid);
      if (!iv) return;
      const q = iv.questions.find((q) => q.id === btn.dataset.qid);
      if (!q) return;
      q.score = parseFloat(btn.dataset.val);
      saveInterviews(interviews);
      renderDetail(container, iv.id);
    } else if (action === "add-q") {
      // handled inside renderForm via rebuildForm
    } else if (action === "guide") {
      // Navigate to Learn tab with the guide open
      const learnBtn = document.querySelector('.nav-item[data-tab="learn"]');
      if (learnBtn) learnBtn.click();
      // Dispatch custom event for app.learn.js to handle
      window.dispatchEvent(new CustomEvent("ilog:open-guide", { detail: { guideId: btn.dataset.guide } }));
    }
  });

  // Form submit
  container.addEventListener("submit", (e) => {
    if (e.target.id === "ilog-form") {
      e.preventDefault();
      saveForm(container);
    }
  });

  // Note auto-save — use both input (live) and change (on blur) so notes
  // are not lost when a score pill is clicked without blurring the textarea first
  const saveNote = (ta) => {
    const interviews = loadInterviews();
    const iv = interviews.find((i) => i.id === ta.dataset.iid);
    if (!iv) return;
    const q = iv.questions.find((q) => q.id === ta.dataset.qid);
    if (!q) return;
    q.notes = ta.value;
    saveInterviews(interviews);
  };
  container.addEventListener("input", (e) => {
    const ta = e.target.closest("[data-ilog-action='note']");
    if (ta) saveNote(ta);
  });
  container.addEventListener("change", (e) => {
    const ta = e.target.closest("[data-ilog-action='note']");
    if (ta) saveNote(ta);
  });
};

// ── Main render ───────────────────────────────────────────────
const renderIlog = (container) => {
  if (ilogState.view === "detail") {
    renderDetail(container, ilogState.activeId);
  } else if (ilogState.view === "form") {
    renderForm(container);
  } else {
    renderDashboard(container);
  }
};

// ── Bootstrap ─────────────────────────────────────────────────
const ilogContainer = document.getElementById("ilog-content");
if (ilogContainer) {
  renderIlog(ilogContainer);
  attachEvents(ilogContainer);
  document.querySelector('.nav-item[data-tab="ilog"]')?.addEventListener("click", () => {
    ilogState.view = "dashboard";
    renderIlog(ilogContainer);
  });
}
